BEGIN;

-- New modules.
INSERT INTO e2e.module (id, slug, name, description, criticality, is_active, created_at, updated_at)
SELECT gen_random_uuid(), 'teams', 'Teams & collaboration', 'Team creation, membership, roles and team documents.', 'p1', true, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM e2e.module WHERE slug = 'teams');

-- New scenarios + their L2 versions.
WITH cat (slug, module_slug, criticality, title, descr, automation_content, steps) AS (
  VALUES
  ('teams.list-teams', 'teams', 'p1', 'Your teams are listed', 'Open the Teams page and see every team you belong to.', 'a3af9664197a00b3', '[{"step_kind":"setup","description":"Open the Teams page.","user_visible_outcome":"The Teams page loads."},{"step_kind":"assert","description":"Every team you belong to is listed.","user_visible_outcome":"Each team shows its name and a way to open it."}]'::jsonb),
  ('teams.create-team', 'teams', 'p0', 'Create a team', 'Create a new team from the Teams page.', '3a77b00ce1403458', '[{"step_kind":"setup","description":"Open the Teams page.","user_visible_outcome":"The Teams page loads."},{"step_kind":"action","action_kind":"click","description":"Click New team."},{"step_kind":"action","action_kind":"type","description":"Enter a name for the team."},{"step_kind":"action","action_kind":"click","description":"Confirm the creation."},{"step_kind":"assert","description":"The team is created.","user_visible_outcome":"The new team appears in your teams list."}]'::jsonb),
  ('teams.rename-team', 'teams', 'p1', 'Rename a team', 'Change a team’s name from its manage dialog.', '403d06890f887cd8', '[{"step_kind":"setup","description":"Open a team you own.","user_visible_outcome":"The team detail page is shown."},{"step_kind":"action","action_kind":"click","description":"Open the team’s manage dialog."},{"step_kind":"action","action_kind":"type","description":"Change the team name."},{"step_kind":"action","action_kind":"click","description":"Save."},{"step_kind":"assert","description":"The team is renamed.","user_visible_outcome":"The team shows the new name everywhere it appears."}]'::jsonb),
