  ('teams.invite-member', 'teams', 'p0', 'Invite a member to a team', 'Invite someone to a team by email.', '491147f367252cce', '[{"step_kind":"setup","description":"Open a team’s detail page as an owner or admin.","user_visible_outcome":"The team detail page is shown."},{"step_kind":"action","action_kind":"click","description":"Open the invite control."},{"step_kind":"action","action_kind":"type","description":"Enter the invitee’s email and pick a role."},{"step_kind":"action","action_kind":"click","description":"Send the invite."},{"step_kind":"assert","description":"The invite is sent.","user_visible_outcome":"The invitee appears as a pending member."}]'::jsonb),
